17	// RBTDRP — pristine-lifecycle fixture for theurge release qualification
18	//
19	// Case 1 (marshal-zero-attestation) is the entry gate for `rbw-tP`. It asserts
20	// that the working tree was just zeroed by `rbw-MZ` (rblm_zero) — five
21	// violation classes are checked and ALL surfaced in one aggregated diagnostic.
22	// Failure short-circuits subsequent cases via the per-fixture fail_fast switch.
23	
24	use std::path::{Path, PathBuf};
25	use std::process::Command;
26	
27	use crate::case;
28	use crate::rbtdrc_crucible::rbtdrc_with_ctx;
29	use crate::rbtdre_engine::{rbtdre_Section, rbtdre_Verdict};
30	use crate::rbtdri_invocation::{rbtdri_invoke_global, rbtdri_read_burv_fact, rbtdri_Context};
31	use crate::rbtdrm_manifest::{
32	    RBTDRM_COLOPHON_DEPOT_LEVY, RBTDRM_COLOPHON_DEPOT_LIST, RBTDRM_COLOPHON_DEPOT_UNMAKE,
33	    RBTDRM_COLOPHON_GOV_FORFEIT, RBTDRM_COLOPHON_GOV_LIST_SAS, RBTDRM_COLOPHON_GOV_MANTLE,
34	};
35	
36	/// RBRR field names referenced by the pristine-lifecycle fixture. Field
37	/// identifiers extracted as consts so the blank-field array and the
38	/// throwaway-prefix install helper share a single definition site.
39	const RBTDRP_FIELD_RBRR_CLOUD_PREFIX: &str = "RBRR_CLOUD_PREFIX";
40	const RBTDRP_FIELD_RBRR_RUNTIME_PREFIX: &str = "RBRR_RUNTIME_PREFIX";
41	const RBTDRP_FIELD_RBRR_DEPOT_MONIKER: &str = "RBRR_DEPOT_MONIKER";
42	
43	/// Site-specific RBRR fields that rblm_zero blanks. These three fields define
44	/// the depot-bound site identity (project ID, GAR repo, pool stem, and bucket
45	/// derive from CLOUD_PREFIX + DEPOT_MONIKER at kindle); an empty value is the
46	/// post-marshal-zero invariant.
47	const RBTDRP_RBRR_BLANK_FIELDS: &[&str] = &[
48	    RBTDRP_FIELD_RBRR_CLOUD_PREFIX,
49	    RBTDRP_FIELD_RBRR_RUNTIME_PREFIX,
50	    RBTDRP_FIELD_RBRR_DEPOT_MONIKER,
51	];
52	
53	/// Throwaway RBRR prefix values stamped into rbrr.env by
54	/// `rbtdrp_install_throwaway_prefixes`. Pristine-lifecycle cases that need
55	/// non-blank prefixes (depot/governor/retriever/director lifecycle) call the
56	/// helper to install these values; the marker shape distinguishes throwaway
57	/// from operator-chosen canonical values.
58	pub(crate) const RBTDRP_THROWAWAY_CLOUD_PREFIX: &str = "prlc-";
59	pub(crate) const RBTDRP_THROWAWAY_RUNTIME_PREFIX: &str = "prlr-";
60	
61	/// Family-stem prefixes for autodetected per-case monikers. Cases pick a
62	/// numeric six-digit suffix at runtime by walking emitted depot fact files
63	/// and incrementing past the highest existing suffix per family. Distinct
64	/// stems keep the two cases' depots separable when both run in the same
65	/// fixture pass.
66	const RBTDRP_FAMILY_STEM_LIFECYCLE: &str = "pristq";
67	const RBTDRP_FAMILY_STEM_GOVERNOR: &str = "pristg";
68	
69	/// Lowest valid numeric suffix for autodetected monikers. Six-digit width
70	/// keeps composed project_id length predictable: cloud_prefix(<=11) +
71	/// "d-"(2) + family(6) + suffix(6) = <=25, well under the 30-char GCP limit.
72	const RBTDRP_FAMILY_NUMERIC_FLOOR: u32 = 100000;
73	
74	/// Six-digit numeric suffix width — enforced when parsing existing fact-file
75	/// names so e.g. "pristq01" (legacy two-digit) is ignored rather than parsed
76	/// as 1 and shadowing real entries.
77	const RBTDRP_FAMILY_NUMERIC_WIDTH: usize = 6;
78	
79	/// Fact-file extension mirror of RBCC_fact_ext_depot in rbcc_Constants.sh.
80	/// rbgp_depot_list emits `<moniker>.depot` files with state content.
81	const RBTDRP_FACT_EXT_DEPOT: &str = "depot";
82	
83	/// Fact-file name for the governor SA email (mirror of
84	/// RBGP_FACT_GOVERNOR_SA_EMAIL from rbgc_Constants.sh). Read from the mantle
85	/// invocation's BURV output.
86	const RBTDRP_FACT_GOVERNOR_SA_EMAIL: &str = "rbgp_fact_governor_sa_email";
87	
88	/// BURE confirmation override (mirrors buc_command.sh): when set to "skip",
89	/// `buc_require` accepts the operation without interactive prompt.
90	const RBTDRP_BURE_CONFIRM_KEY: &str = "BURE_CONFIRM";
91	const RBTDRP_BURE_CONFIRM_SKIP: &str = "skip";
92	
93	/// `DELETE_REQUESTED` lifecycle state — appears in `rbgp_depot_list` output
94	/// after a soft-delete, used by case 2 to relax the post-unmake assertion.
95	const RBTDRP_DELETE_REQUESTED: &str = "DELETE_REQUESTED";
96	
97	/// Roles whose RBRA credential files rblm_zero deletes.
98	const RBTDRP_RBRA_ROLES: &[&str] = &["governor", "director", "retriever", "assay"];
99	
100	/// Nameplate hallmark fields rblm_zero blanks.
101	const RBTDRP_RBRN_BLANK_FIELDS: &[&str] = &["RBRN_SENTRY_HALLMARK", "RBRN_BOTTLE_HALLMARK"];
102	
103	/// File-relative constants matching rbbc_constants.sh / rbcc_Constants.sh.
104	const RBTDRP_DOT_DIR: &str = ".rbk";
105	const RBTDRP_RBRR_FILE: &str = ".rbk/rbrr.env";
106	const RBTDRP_RBRA_FILE: &str = "rbra.env";
107	const RBTDRP_RBRN_FILE: &str = "rbrn.env";
108	const RBTDRP_RBRV_FILE: &str = "rbrv.env";
109	
110	// ── Helpers ──────────────────────────────────────────────────
111	
112	/// Read an env file and return the value for `key`, or None if the key is
113	/// absent. The bash regime files use `KEY=value` lines (unquoted); comment
114	/// and blank lines are skipped. The trailing newline is stripped from value.
115	fn rbtdrp_read_env_value(path: &Path, key: &str) -> Option<String> {
116	    let content = std::fs::read_to_string(path).ok()?;
117	    let prefix = format!("{}=", key);
118	    for line in content.lines() {
119	        let trimmed = line.trim_start();
120	        if trimmed.starts_with('#') {
121	            continue;
122	        }
123	        if let Some(rest) = trimmed.strip_prefix(&prefix) {
124	            return Some(rest.to_string());
125	        }
126	    }
127	    None
128	}
129	
130	/// Resolve a path that may be absolute or relative-to-project-root.
131	fn rbtdrp_resolve(root: &Path, raw: &str) -> PathBuf {
132	    if Path::new(raw).is_absolute() {
133	        PathBuf::from(raw)
134	    } else {
135	        root.join(raw)
136	    }
137	}
138	
139	/// Class A — working tree clean (`git status --porcelain` empty).
140	fn rbtdrp_check_tree_clean(root: &Path, violations: &mut Vec<String>) {
141	    match Command::new("git")
142	        .args(["status", "--porcelain"])
143	        .current_dir(root)
144	        .output()
145	    {
146	        Ok(out) if out.status.success() => {
147	            let stdout = String::from_utf8_lossy(&out.stdout);
148	            let trimmed = stdout.trim();
149	            if !trimmed.is_empty() {
150	                violations.push(format!(
151	                    "working tree not clean — uncommitted changes:\n{}",
152	                    trimmed
153	                ));
154	            }
155	        }
156	        Ok(out) => violations.push(format!(
157	            "git status --porcelain failed (exit {}): {}",
158	            out.status.code().unwrap_or(-1),
159	            String::from_utf8_lossy(&out.stderr).trim()
160	        )),
161	        Err(e) => violations.push(format!("git status invocation failed: {}", e)),
162	    }
163	}
164	
165	/// Class B — five site-specific RBRR fields are blank.
166	fn rbtdrp_check_rbrr_fields(rbrr: &Path, violations: &mut Vec<String>) {
167	    for field in RBTDRP_RBRR_BLANK_FIELDS {
168	        if let Some(value) = rbtdrp_read_env_value(rbrr, field) {
169	            if !value.is_empty() {
170	                violations.push(format!(
171	                    "RBRR field non-blank: {}={} (in {})",
172	                    field,
173	                    value,
174	                    rbrr.display()
175	                ));
176	            }
177	        }
178	    }
179	}
180	
181	/// Class C — no RBRA credential files at the four role paths.
182	fn rbtdrp_check_rbra_files(root: &Path, secrets_dir: &str, violations: &mut Vec<String>) {
183	    if secrets_dir.is_empty() {
184	        violations.push(
185	            "RBRR_SECRETS_DIR is blank — cannot resolve credential paths".to_string(),
186	        );
187	        return;
188	    }
189	    let secrets = rbtdrp_resolve(root, secrets_dir);
190	    for role in RBTDRP_RBRA_ROLES {
191	        let path = secrets.join(role).join(RBTDRP_RBRA_FILE);
192	        if path.exists() {
193	            violations.push(format!("RBRA credential present: {}", path.display()));
194	        }
195	    }
196	}
197	
198	/// Class D — every nameplate's RBRN_SENTRY_HALLMARK and RBRN_BOTTLE_HALLMARK
199	/// is blank.
200	fn rbtdrp_check_nameplate_hallmarks(root: &Path, violations: &mut Vec<String>) {
201	    let dot_dir = root.join(RBTDRP_DOT_DIR);
202	    let entries = match std::fs::read_dir(&dot_dir) {
203	        Ok(e) => e,
204	        Err(e) => {
205	            violations.push(format!("cannot read {}: {}", dot_dir.display(), e));
206	            return;
207	        }
208	    };
209	    for entry in entries.flatten() {
210	        let np_dir = entry.path();
211	        if !np_dir.is_dir() {
212	            continue;
213	        }
214	        let rbrn = np_dir.join(RBTDRP_RBRN_FILE);
215	        if !rbrn.exists() {
216	            continue;
217	        }
218	        for field in RBTDRP_RBRN_BLANK_FIELDS {
219	            if let Some(value) = rbtdrp_read_env_value(&rbrn, field) {
220	                if !value.is_empty() {
221	                    violations.push(format!(
222	                        "nameplate hallmark non-blank: {}={} (in {})",
223	                        field,
224	                        value,
225	                        rbrn.display()
226	                    ));
227	                }
228	            }
229	        }
230	    }
231	}
232	
233	/// Class E — every vessel rbrv.env has RBRV_RELIQUARY blank and every
234	/// RBRV_IMAGE_*_ANCHOR field blank.
235	fn rbtdrp_check_vessel_depot_fields(
236	    root: &Path,
237	    vessel_dir: &str,
238	    violations: &mut Vec<String>,
239	) {
240	    if vessel_dir.is_empty() {
241	        violations.push("RBRR_VESSEL_DIR is blank — cannot scan vessels".to_string());
242	        return;
243	    }
244	    let vroot = rbtdrp_resolve(root, vessel_dir);
245	    let entries = match std::fs::read_dir(&vroot) {
246	        Ok(e) => e,
247	        Err(e) => {
248	            violations.push(format!("cannot read {}: {}", vroot.display(), e));
249	            return;
250	        }
251	    };
252	    for entry in entries.flatten() {
253	        let v_dir = entry.path();
254	        if !v_dir.is_dir() {
255	            continue;
256	        }
257	        let rbrv = v_dir.join(RBTDRP_RBRV_FILE);
258	        if !rbrv.exists() {
259	            continue;
260	        }
261	        rbtdrp_scan_rbrv_file(&rbrv, violations);
262	    }
263	}
264	
265	/// Scan a single rbrv.env for non-blank RBRV_RELIQUARY and RBRV_IMAGE_*_ANCHOR
266	/// fields.
267	fn rbtdrp_scan_rbrv_file(rbrv: &Path, violations: &mut Vec<String>) {
268	    let content = match std::fs::read_to_string(rbrv) {
269	        Ok(c) => c,
270	        Err(e) => {
271	            violations.push(format!("cannot read {}: {}", rbrv.display(), e));
272	            return;
273	        }
274	    };
275	    for line in content.lines() {
276	        let trimmed = line.trim_start();
277	        if trimmed.starts_with('#') {
278	            continue;
279	        }
280	        let (key, value) = match trimmed.split_once('=') {
281	            Some(kv) => kv,
282	            None => continue,
283	        };
284	        let is_reliquary = key == "RBRV_RELIQUARY";
285	        let is_anchor = key.starts_with("RBRV_IMAGE_") && key.ends_with("_ANCHOR");
286	        if (is_reliquary || is_anchor) && !value.is_empty() {
287	            violations.push(format!(
288	                "vessel depot-scoped field non-blank: {}={} (in {})",
289	                key,
290	                value,
291	                rbrv.display()
292	            ));
293	        }
294	    }
295	}
296	
297	// ── Env-file rewrite + git commit helpers ────────────────────
298	
299	/// Rewrite each line in `content` whose key matches an entry in `pairs`
300	/// (matched as `KEY=`) to `KEY=value`. Lines whose keys are not in `pairs`
301	/// pass through unchanged. The trailing-newline shape is preserved.
302	fn rbtdrp_replace_env_fields(content: &str, pairs: &[(&str, &str)]) -> String {
303	    let mut result: String = content
304	        .lines()
305	        .map(|line| {
306	            for (key, value) in pairs {
307	                let assign = format!("{}=", key);
308	                if line.starts_with(&assign) {
309	                    return format!("{}{}", assign, value);
310	                }
311	            }
312	            line.to_string()
313	        })
314	        .collect::<Vec<_>>()
315	        .join("\n");
316	    if content.ends_with('\n') {
317	        result.push('\n');
318	    }
319	    result
320	}
321	
322	/// `git add <file> && git commit -m <message>` from `root`. Bubbles the
323	/// underlying stderr on either step's failure.
324	fn rbtdrp_git_add_and_commit(root: &Path, file: &str, message: &str) -> Result<(), String> {
325	    let add = Command::new("git")
326	        .args(["add", file])
327	        .current_dir(root)
328	        .output()
329	        .map_err(|e| format!("rbtdrp: git add invocation failed: {}", e))?;
330	    if !add.status.success() {
331	        return Err(format!(
332	            "rbtdrp: git add failed (exit {}): {}",
333	            add.status.code().unwrap_or(-1),
334	            String::from_utf8_lossy(&add.stderr).trim()
335	        ));
336	    }
337	
338	    let commit = Command::new("git")
339	        .args(["commit", "-m", message])
340	        .current_dir(root)
341	        .output()
342	        .map_err(|e| format!("rbtdrp: git commit invocation failed: {}", e))?;
343	    if !commit.status.success() {
344	        return Err(format!(
345	            "rbtdrp: git commit failed (exit {}): {}",
346	            commit.status.code().unwrap_or(-1),
347	            String::from_utf8_lossy(&commit.stderr).trim()
348	        ));
349	    }
350	
351	    Ok(())
352	}
353	
354	// ── Throwaway-prefix install ─────────────────────────────────
355	
356	/// Idempotently install throwaway RBRR prefixes into `.rbk/rbrr.env`.
357	///
358	/// Pristine-lifecycle cases that need non-blank prefixes (depot/governor/
359	/// retriever/director lifecycle) call this as their first step. The helper
360	/// reads current values; if `RBRR_CLOUD_PREFIX` and `RBRR_RUNTIME_PREFIX`
361	/// already match the throwaway markers, returns `Ok(())` with no side
362	/// effect. Otherwise rewrites both lines in place, then `git add` +
363	/// `git commit` the change. One commit per fixture run regardless of which
364	/// case is the first to call it.
365	///
366	/// HEAD walks off marshal-zero after the commit; recovery is `rbw-MZ`,
367	/// matching the pristine fixture's start-over-from-zero failure mode.
368	pub(crate) fn rbtdrp_install_throwaway_prefixes(root: &Path) -> Result<(), String> {
369	    let rbrr = root.join(RBTDRP_RBRR_FILE);
370	    let cloud = rbtdrp_read_env_value(&rbrr, RBTDRP_FIELD_RBRR_CLOUD_PREFIX).unwrap_or_default();
371	    let runtime =
372	        rbtdrp_read_env_value(&rbrr, RBTDRP_FIELD_RBRR_RUNTIME_PREFIX).unwrap_or_default();
373	
374	    if cloud == RBTDRP_THROWAWAY_CLOUD_PREFIX && runtime == RBTDRP_THROWAWAY_RUNTIME_PREFIX {
375	        return Ok(());
376	    }
377	
378	    let content = std::fs::read_to_string(&rbrr)
379	        .map_err(|e| format!("rbtdrp: read {}: {}", rbrr.display(), e))?;
380	    let new_content = rbtdrp_replace_env_fields(
381	        &content,
382	        &[
383	            (RBTDRP_FIELD_RBRR_CLOUD_PREFIX, RBTDRP_THROWAWAY_CLOUD_PREFIX),
384	            (
385	                RBTDRP_FIELD_RBRR_RUNTIME_PREFIX,
386	                RBTDRP_THROWAWAY_RUNTIME_PREFIX,
387	            ),
388	        ],
389	    );
390	    std::fs::write(&rbrr, &new_content)
391	        .map_err(|e| format!("rbtdrp: write {}: {}", rbrr.display(), e))?;
392	
393	    let commit_msg = format!(
394	        "pristine-lifecycle fixture: install throwaway RBRR prefixes ({}/{})",
395	        RBTDRP_THROWAWAY_CLOUD_PREFIX, RBTDRP_THROWAWAY_RUNTIME_PREFIX
396	    );
397	    rbtdrp_git_add_and_commit(root, RBTDRP_RBRR_FILE, &commit_msg)
398	}
399	
400	/// Pick the next free moniker for `family_stem` by walking the depot_list
401	/// invocation's BURV output dir for `<family>NNNNNN.depot` files, parsing
402	/// the numeric suffix from each, and returning `<family><max + 1>`. Returns
403	/// `<family>RBTDRP_FAMILY_NUMERIC_FLOOR` when no matching files exist or the
404	/// output dir is missing (first run, no prior depots).
405	fn rbtdrp_pick_next_moniker(
406	    list_result: &crate::rbtdri_invocation::rbtdri_InvokeResult,
407	    family_stem: &str,
408	) -> Result<String, String> {
409	    let dir = list_result
410	        .burv_output
411	        .join(crate::rbtdri_invocation::RBTDRI_BURV_OUTPUT_SUBDIR);
412	
413	    let entries = match std::fs::read_dir(&dir) {
414	        Ok(e) => e,
415	        Err(_) => {
416	            return Ok(format!("{}{}", family_stem, RBTDRP_FAMILY_NUMERIC_FLOOR));
417	        }
418	    };
419	
420	    let suffix_ext = format!(".{}", RBTDRP_FACT_EXT_DEPOT);
421	    let mut max_suffix: Option<u32> = None;
422	    for entry in entries.flatten() {
423	        let name = match entry.file_name().into_string() {
424	            Ok(n) => n,
425	            Err(_) => continue,
426	        };
427	        let stem = match name.strip_suffix(&suffix_ext) {
428	            Some(s) => s,
429	            None => continue,
430	        };
431	        let numeric = match stem.strip_prefix(family_stem) {
432	            Some(s) => s,
433	            None => continue,
434	        };
435	        if numeric.len() != RBTDRP_FAMILY_NUMERIC_WIDTH {
436	            continue;
437	        }
438	        let parsed: u32 = match numeric.parse() {
439	            Ok(n) => n,
440	            Err(_) => continue,
441	        };
442	        max_suffix = Some(max_suffix.map_or(parsed, |m| m.max(parsed)));
443	    }
444	
445	    let next = match max_suffix {
446	        Some(m) => m + 1,
447	        None => RBTDRP_FAMILY_NUMERIC_FLOOR,
448	    };
449	    Ok(format!("{}{}", family_stem, next))
450	}
451	
452	/// Compose the depot project_id from kindled regime values. Mirrors RBDC's
453	/// derivation: `${RBRR_CLOUD_PREFIX}d-${moniker}`. Used by cases 2 and 3 to
454	/// recover the project_id post-levy without re-reading a fact file (the
455	/// pre-collapse `rbgp_fact_depot_project_id` producer is gone).
456	fn rbtdrp_compose_project_id(root: &Path, moniker: &str) -> Result<String, String> {
457	    let rbrr = root.join(RBTDRP_RBRR_FILE);
458	    let cloud_prefix = rbtdrp_read_env_value(&rbrr, RBTDRP_FIELD_RBRR_CLOUD_PREFIX)
459	        .ok_or_else(|| format!("RBRR_CLOUD_PREFIX missing from {}", rbrr.display()))?;
460	    Ok(format!("{}d-{}", cloud_prefix, moniker))
461	}
462	
463	/// Set `RBRR_DEPOT_MONIKER` in rbrr.env to `moniker` and commit. Cases 2-3
464	/// use this to install a moniker that drives `RBDC_DEPOT_PROJECT_ID` via
465	/// kindle derivation. The commit is separate from the throwaway-prefix
466	/// commit so the audit trail shows the moniker landing as its own pace.
467	fn rbtdrp_install_depot_moniker(root: &Path, moniker: &str) -> Result<(), String> {
468	    let rbrr = root.join(RBTDRP_RBRR_FILE);
469	    let content = std::fs::read_to_string(&rbrr)
470	        .map_err(|e| format!("rbtdrp: read {}: {}", rbrr.display(), e))?;
471	    let new_content = rbtdrp_replace_env_fields(
472	        &content,
473	        &[(RBTDRP_FIELD_RBRR_DEPOT_MONIKER, moniker)],
474	    );
475	    std::fs::write(&rbrr, &new_content)
476	        .map_err(|e| format!("rbtdrp: write {}: {}", rbrr.display(), e))?;
477	
478	    let commit_msg = format!(
479	        "pristine-lifecycle fixture: set {}={}",
480	        RBTDRP_FIELD_RBRR_DEPOT_MONIKER, moniker
481	    );
482	    rbtdrp_git_add_and_commit(root, RBTDRP_RBRR_FILE, &commit_msg)
483	}
484	
485	// ── Case ─────────────────────────────────────────────────────
486	
487	/// Case 1 — marshal-zero attestation. Aggregates all five violation classes
488	/// into a single diagnostic. A passing run is the proof that `rbw-MZ` was
489	/// just executed and committed.
490	fn rbtdrp_marshal_zero_attestation(_dir: &Path) -> rbtdre_Verdict {
491	    let root = match std::env::current_dir() {
492	        Ok(r) => r,
493	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot resolve project root: {}", e)),
494	    };
495	
496	    let rbrr = root.join(RBTDRP_RBRR_FILE);
497	    if !rbrr.exists() {
498	        return rbtdre_Verdict::Fail(format!("RBRR file not found: {}", rbrr.display()));
499	    }
500	
501	    let secrets_dir = rbtdrp_read_env_value(&rbrr, "RBRR_SECRETS_DIR").unwrap_or_default();
502	    let vessel_dir = rbtdrp_read_env_value(&rbrr, "RBRR_VESSEL_DIR").unwrap_or_default();
503	
504	    let mut violations: Vec<String> = Vec::new();
505	
506	    rbtdrp_check_tree_clean(&root, &mut violations);
507	    rbtdrp_check_rbrr_fields(&rbrr, &mut violations);
508	    rbtdrp_check_rbra_files(&root, &secrets_dir, &mut violations);
509	    rbtdrp_check_nameplate_hallmarks(&root, &mut violations);
510	    rbtdrp_check_vessel_depot_fields(&root, &vessel_dir, &mut violations);
511	
512	    if violations.is_empty() {
513	        return rbtdre_Verdict::Pass;
514	    }
515	
516	    let body = violations
517	        .iter()
518	        .map(|v| format!("  - {}", v))
519	        .collect::<Vec<_>>()
520	        .join("\n");
521	    rbtdre_Verdict::Fail(format!(
522	        "marshal-zero attestation failed — {} violation(s):\n{}\n\n\
523	         remedy: tt/rbw-MZ.MarshalZeroes.sh, then commit and rerun.",
524	        violations.len(),
525	        body
526	    ))
527	}
528	
529	// ── Cases 2 & 3 — depot and governor lifecycles ──────────────
530	
531	/// Wrapper invocation: call `rbtdri_invoke_global` and tee stdout/stderr to
532	/// `dir/<label>-stdout.txt` / `dir/<label>-stderr.txt` for diagnostic review.
533	/// Returns `Ok(InvokeResult)` regardless of exit code; callers decide what
534	/// counts as failure.
535	fn rbtdrp_invoke_logged(
536	    ctx: &mut rbtdri_Context,
537	    colophon: &str,
538	    args: &[&str],
539	    extra_env: &[(&str, &str)],
540	    dir: &Path,
541	    label: &str,
542	) -> Result<crate::rbtdri_invocation::rbtdri_InvokeResult, String> {
543	    let result = rbtdri_invoke_global(ctx, colophon, args, extra_env)?;
544	    let _ = std::fs::write(dir.join(format!("{}-stdout.txt", label)), &result.stdout);
545	    let _ = std::fs::write(dir.join(format!("{}-stderr.txt", label)), &result.stderr);
546	    Ok(result)
547	}
548	
549	/// Case 2 — depot-lifecycle. Probes existing depots via `rbgp_depot_list`,
550	/// picks the next free six-digit moniker in the `pristq` family, levies the
551	/// depot, asserts it appears in a follow-up `rbgp_depot_list`, soft-deletes
552	/// it via `rbgp_depot_unmake`, then asserts it is absent or in
553	/// `DELETE_REQUESTED` state.
554	///
555	/// Levy and unmake are zero-arg post-collapse — the moniker is set in
556	/// rbrr.env via `rbtdrp_install_depot_moniker` before levy invocation, and
557	/// the project_id is composed from regime values via `rbtdrp_compose_project_id`.
558	fn rbtdrp_depot_lifecycle(dir: &Path) -> rbtdre_Verdict {
559	    rbtdrc_with_ctx(|ctx| rbtdrp_depot_lifecycle_impl(ctx, dir))
560	}
561	
562	fn rbtdrp_depot_lifecycle_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
563	    let root = ctx.project_root().to_path_buf();
564	
565	    if let Err(e) = rbtdrp_install_throwaway_prefixes(&root) {
566	        return rbtdre_Verdict::Fail(format!("install throwaway prefixes: {}", e));
567	    }
568	
569	    let list_pre = match rbtdrp_invoke_logged(
570	        ctx,
571	        RBTDRM_COLOPHON_DEPOT_LIST,
572	        &[],
573	        &[],
574	        dir,
575	        "list-pre",
576	    ) {
577	        Ok(r) => r,
578	        Err(e) => return rbtdre_Verdict::Fail(format!("depot list (pre-levy probe): {}", e)),
579	    };
580	    if list_pre.exit_code != 0 {
581	        return rbtdre_Verdict::Fail(format!(
582	            "depot list (pre-levy probe) exit {}\n{}",
583	            list_pre.exit_code, list_pre.stderr
584	        ));
585	    }
586	
587	    let moniker = match rbtdrp_pick_next_moniker(&list_pre, RBTDRP_FAMILY_STEM_LIFECYCLE) {
588	        Ok(m) => m,
589	        Err(e) => return rbtdre_Verdict::Fail(format!("pick next moniker: {}", e)),
590	    };
591	    if let Err(e) = rbtdrp_install_depot_moniker(&root, &moniker) {
592	        return rbtdre_Verdict::Fail(format!("install depot moniker: {}", e));
593	    }
594	
595	    let levy = match rbtdrp_invoke_logged(
596	        ctx,
597	        RBTDRM_COLOPHON_DEPOT_LEVY,
598	        &[],
599	        &[],
600	        dir,
601	        "levy",
602	    ) {
603	        Ok(r) => r,
604	        Err(e) => return rbtdre_Verdict::Fail(format!("depot levy: {}", e)),
605	    };
606	    if levy.exit_code != 0 {
607	        return rbtdre_Verdict::Fail(format!(
608	            "depot levy exit {}\n{}",
609	            levy.exit_code, levy.stderr
610	        ));
611	    }
612	
613	    let project_id = match rbtdrp_compose_project_id(&root, &moniker) {
614	        Ok(p) => p,
615	        Err(e) => return rbtdre_Verdict::Fail(format!("compose project_id: {}", e)),
616	    };
617	    let _ = std::fs::write(dir.join("project-id.txt"), &project_id);
618	
619	    let list_present = match rbtdrp_invoke_logged(
620	        ctx,
621	        RBTDRM_COLOPHON_DEPOT_LIST,
622	        &[],
623	        &[],
624	        dir,
625	        "list-present",
626	    ) {
627	        Ok(r) => r,
628	        Err(e) => return rbtdre_Verdict::Fail(format!("depot list (after levy): {}", e)),
629	    };
630	    if list_present.exit_code != 0 {
631	        return rbtdre_Verdict::Fail(format!(
632	            "depot list (after levy) exit {}\n{}",
633	            list_present.exit_code, list_present.stderr
634	        ));
635	    }
636	    if !list_present.stdout.contains(&project_id) {
637	        return rbtdre_Verdict::Fail(format!(
638	            "project_id '{}' missing from depot list after levy:\n{}",
639	            project_id, list_present.stdout
640	        ));
641	    }
642	
643	    let unmake = match rbtdrp_invoke_logged(
644	        ctx,
645	        RBTDRM_COLOPHON_DEPOT_UNMAKE,
646	        &[],
647	        &[(RBTDRP_BURE_CONFIRM_KEY, RBTDRP_BURE_CONFIRM_SKIP)],
648	        dir,
649	        "unmake",
650	    ) {
651	        Ok(r) => r,
652	        Err(e) => return rbtdre_Verdict::Fail(format!("depot unmake: {}", e)),
653	    };
654	    if unmake.exit_code != 0 {
655	        return rbtdre_Verdict::Fail(format!(
656	            "depot unmake exit {}\n{}",
657	            unmake.exit_code, unmake.stderr
658	        ));
659	    }
660	
661	    let list_after = match rbtdrp_invoke_logged(
662	        ctx,
663	        RBTDRM_COLOPHON_DEPOT_LIST,
664	        &[],
665	        &[],
666	        dir,
667	        "list-after",
668	    ) {
669	        Ok(r) => r,
670	        Err(e) => return rbtdre_Verdict::Fail(format!("depot list (after unmake): {}", e)),
671	    };
672	    if list_after.exit_code != 0 {
673	        return rbtdre_Verdict::Fail(format!(
674	            "depot list (after unmake) exit {}\n{}",
675	            list_after.exit_code, list_after.stderr
676	        ));
677	    }
678	    for line in list_after.stdout.lines() {
679	        if line.contains(&project_id) && !line.contains(RBTDRP_DELETE_REQUESTED) {
680	            return rbtdre_Verdict::Fail(format!(
681	                "project_id '{}' still present without {} after unmake:\n{}",
682	                project_id, RBTDRP_DELETE_REQUESTED, line
683	            ));
684	        }
685	    }
686	
687	    rbtdre_Verdict::Pass
688	}
689	
690	/// Case 3 — governor-lifecycle. Probes existing depots, picks the next free
691	/// moniker in the `pristg` family, levies its own throwaway depot (so
692	/// `RBDC_DEPOT_PROJECT_ID` is set via kindle derivation, satisfying the
693	/// precondition for `rbgp_governor_mantle`), mantles a governor, asserts it
694	/// appears in `rbgg_list_service_accounts`, forfeits it, asserts absent,
695	/// then unmakes the depot to clean up.
696	///
697	/// `pristg` family stem keeps governor monikers separable from `pristq`
698	/// (case 2) when the full fixture runs.
699	fn rbtdrp_governor_lifecycle(dir: &Path) -> rbtdre_Verdict {
700	    rbtdrc_with_ctx(|ctx| rbtdrp_governor_lifecycle_impl(ctx, dir))
701	}
702	
703	fn rbtdrp_governor_lifecycle_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
704	    let root = ctx.project_root().to_path_buf();
705	
706	    if let Err(e) = rbtdrp_install_throwaway_prefixes(&root) {
707	        return rbtdre_Verdict::Fail(format!("install throwaway prefixes: {}", e));
708	    }
709	
710	    let list_pre = match rbtdrp_invoke_logged(
711	        ctx,
712	        RBTDRM_COLOPHON_DEPOT_LIST,
713	        &[],
714	        &[],
715	        dir,
716	        "list-pre",
717	    ) {
718	        Ok(r) => r,
719	        Err(e) => return rbtdre_Verdict::Fail(format!("depot list (pre-levy probe): {}", e)),
720	    };
721	    if list_pre.exit_code != 0 {
722	        return rbtdre_Verdict::Fail(format!(
723	            "depot list (pre-levy probe) exit {}\n{}",
724	            list_pre.exit_code, list_pre.stderr
725	        ));
726	    }
727	
728	    let moniker = match rbtdrp_pick_next_moniker(&list_pre, RBTDRP_FAMILY_STEM_GOVERNOR) {
729	        Ok(m) => m,
730	        Err(e) => return rbtdre_Verdict::Fail(format!("pick next moniker: {}", e)),
731	    };
732	    if let Err(e) = rbtdrp_install_depot_moniker(&root, &moniker) {
733	        return rbtdre_Verdict::Fail(format!("install depot moniker: {}", e));
734	    }
735	
736	    let levy = match rbtdrp_invoke_logged(
737	        ctx,
738	        RBTDRM_COLOPHON_DEPOT_LEVY,
739	        &[],
740	        &[],
741	        dir,
742	        "levy",
743	    ) {
744	        Ok(r) => r,
745	        Err(e) => return rbtdre_Verdict::Fail(format!("depot levy: {}", e)),
746	    };
747	    if levy.exit_code != 0 {
748	        return rbtdre_Verdict::Fail(format!(
749	            "depot levy exit {}\n{}",
750	            levy.exit_code, levy.stderr
751	        ));
752	    }
753	
754	    let project_id = match rbtdrp_compose_project_id(&root, &moniker) {
755	        Ok(p) => p,
756	        Err(e) => return rbtdre_Verdict::Fail(format!("compose project_id: {}", e)),
757	    };
758	    let _ = std::fs::write(dir.join("project-id.txt"), &project_id);
759	
760	    let mantle = match rbtdrp_invoke_logged(
761	        ctx,
762	        RBTDRM_COLOPHON_GOV_MANTLE,
763	        &[],
764	        &[],
765	        dir,
766	        "mantle",
767	    ) {
768	        Ok(r) => r,
769	        Err(e) => return rbtdre_Verdict::Fail(format!("governor mantle: {}", e)),
770	    };
771	    if mantle.exit_code != 0 {
772	        return rbtdre_Verdict::Fail(format!(
773	            "governor mantle exit {}\n{}",
774	            mantle.exit_code, mantle.stderr
775	        ));
776	    }
777	
778	    let sa_email = match rbtdri_read_burv_fact(&mantle, RBTDRP_FACT_GOVERNOR_SA_EMAIL) {
779	        Ok(s) => s,
780	        Err(e) => return rbtdre_Verdict::Fail(format!("read governor SA email fact: {}", e)),
781	    };
782	    let _ = std::fs::write(dir.join("sa-email.txt"), &sa_email);
783	
784	    let list_present = match rbtdrp_invoke_logged(
785	        ctx,
786	        RBTDRM_COLOPHON_GOV_LIST_SAS,
787	        &[],
788	        &[],
789	        dir,
790	        "list-present",
791	    ) {
792	        Ok(r) => r,
793	        Err(e) => return rbtdre_Verdict::Fail(format!("list SAs (after mantle): {}", e)),
794	    };
795	    if list_present.exit_code != 0 {
796	        return rbtdre_Verdict::Fail(format!(
797	            "list SAs (after mantle) exit {}\n{}",
798	            list_present.exit_code, list_present.stderr
799	        ));
800	    }
801	    if !list_present.stdout.contains(&sa_email) {
802	        return rbtdre_Verdict::Fail(format!(
803	            "governor SA '{}' missing from list after mantle:\n{}",
804	            sa_email, list_present.stdout
805	        ));
806	    }
807	
808	    let forfeit = match rbtdrp_invoke_logged(
809	        ctx,
810	        RBTDRM_COLOPHON_GOV_FORFEIT,
811	        &[&sa_email],
812	        &[],
813	        dir,
814	        "forfeit",
815	    ) {
816	        Ok(r) => r,
817	        Err(e) => return rbtdre_Verdict::Fail(format!("governor forfeit: {}", e)),
818	    };
819	    if forfeit.exit_code != 0 {
820	        return rbtdre_Verdict::Fail(format!(
821	            "governor forfeit exit {}\n{}",
822	            forfeit.exit_code, forfeit.stderr
823	        ));
824	    }
825	
826	    let list_after = match rbtdrp_invoke_logged(
827	        ctx,
828	        RBTDRM_COLOPHON_GOV_LIST_SAS,
829	        &[],
830	        &[],
831	        dir,
832	        "list-after",
833	    ) {
834	        Ok(r) => r,
835	        Err(e) => return rbtdre_Verdict::Fail(format!("list SAs (after forfeit): {}", e)),
836	    };
837	    if list_after.exit_code != 0 {
838	        return rbtdre_Verdict::Fail(format!(
839	            "list SAs (after forfeit) exit {}\n{}",
840	            list_after.exit_code, list_after.stderr
841	        ));
842	    }
843	    if list_after.stdout.contains(&sa_email) {
844	        return rbtdre_Verdict::Fail(format!(
845	            "governor SA '{}' still present after forfeit:\n{}",
846	            sa_email, list_after.stdout
847	        ));
848	    }
849	
850	    let unmake = match rbtdrp_invoke_logged(
851	        ctx,
852	        RBTDRM_COLOPHON_DEPOT_UNMAKE,
853	        &[],
854	        &[(RBTDRP_BURE_CONFIRM_KEY, RBTDRP_BURE_CONFIRM_SKIP)],
855	        dir,
856	        "unmake",
857	    ) {
858	        Ok(r) => r,
859	        Err(e) => return rbtdre_Verdict::Fail(format!("depot unmake (cleanup): {}", e)),
860	    };
861	    if unmake.exit_code != 0 {
862	        return rbtdre_Verdict::Fail(format!(
863	            "depot unmake (cleanup) exit {}\n{}",
864	            unmake.exit_code, unmake.stderr
865	        ));
866	    }
867	
868	    rbtdre_Verdict::Pass
869	}
870	
871	// ── Section registry ─────────────────────────────────────────
872	
873	pub static RBTDRP_SECTIONS_PRISTINE_LIFECYCLE: &[rbtdre_Section] = &[
874	    rbtdre_Section {
875	        name: "pristine-lifecycle-gate",
876	        cases: &[case!(rbtdrp_marshal_zero_attestation)],
877	    },
878	    rbtdre_Section {
879	        name: "pristine-lifecycle-simple",
880	        cases: &[
881	            case!(rbtdrp_depot_lifecycle),
882	            case!(rbtdrp_governor_lifecycle),
883	        ],
884	    },
885	];
