567	/// it via `rbgp_depot_unmake`, then asserts it is absent or in
568	/// `DELETE_REQUESTED` state.
569	///
570	/// Levy and unmake are zero-arg post-collapse — the moniker is set in
571	/// rbrr.env via `rbtdrp_install_depot_moniker` before levy invocation, and
572	/// the project_id is composed from regime values via `rbtdrp_compose_project_id`.
573	fn rbtdrp_depot_lifecycle(dir: &Path) -> rbtdre_Verdict {
574	    rbtdrc_with_ctx(|ctx| rbtdrp_depot_lifecycle_impl(ctx, dir))
575	}
576	
577	fn rbtdrp_depot_lifecycle_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
578	    let root = ctx.project_root().to_path_buf();
579	
580	    if let Err(e) = rbtdrp_install_throwaway_prefixes(&root) {
581	        return rbtdre_Verdict::Fail(format!("install throwaway prefixes: {}", e));
582	    }
583	
584	    let list_pre = match rbtdrp_invoke_logged(
585	        ctx,
