587	        &[],
588	        &[],
589	        dir,
590	        "list-pre",
591	    ) {
592	        Ok(r) => r,
593	        Err(e) => return rbtdre_Verdict::Fail(format!("depot list (pre-levy probe): {}", e)),
594	    };
595	    if list_pre.exit_code != 0 {
596	        return rbtdre_Verdict::Fail(format!(
597	            "depot list (pre-levy probe) exit {}\n{}",
